class Solution:
    def maxLevelSum(self, root):
        sums = {}
        def walk(node, depth):
            if not node:
                return
            sums[depth] = sums.get(depth, 0) + node.val
            walk(node.left, depth + 1)
            walk(node.right, depth + 1)
        walk(root, 1)
        best_level = 1
        best_sum = None
        for d in sorted(sums):
            if best_sum is None or sums[d] > best_sum:
                best_sum = sums[d]
                best_level = d
        return best_level

