class Solution:
    def maxLevelSum(self, root):
        level = [root] if root else []
        best_level = 0
        best_sum = None
        depth = 0
        while level:
            depth += 1
            total = sum(n.val for n in level)
            if best_sum is None or total > best_sum:
                best_sum = total
                best_level = depth
            nxt = []
            for n in level:
                if n.left:
                    nxt.append(n.left)
                if n.right:
                    nxt.append(n.right)
            level = nxt
        return best_level

