var maxLevelSum = function(root) {
    let level = root ? [root] : [];
    let bestLevel = 0, bestSum = null, depth = 0;
    while (level.length) {
        depth++;
        let total = 0;
        for (const n of level) total += n.val;
        if (bestSum === null || total > bestSum) {
            bestSum = total;
            bestLevel = depth;
        }
        const nxt = [];
        for (const n of level) {
            if (n.left) nxt.push(n.left);
            if (n.right) nxt.push(n.right);
        }
        level = nxt;
    }
    return bestLevel;
};
